1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	interface Item {
11	  type: string;
12	}
13	
14	interface QuoteStep {
15	  op: "quote";
16	  items: Item[];
17	}
18	
19	interface Scenario {
20	  customer: { yearsWithMHPCO: number };
21	  steps: QuoteStep[];
22	}
23	
24	const itemPremium = (item: Item): number => {
25	  const base = BASE_PREMIUM_BY_TYPE[item.type];
26	  return Math.ceil(base + base * FIRST_INSURANCE_SURCHARGE);
27	};
28	
29	const quoteStep = (step: QuoteStep) => {
30	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
31	  return { premium: itemsTotal + PROCESSING_FEE };
32	};
33	
34	export const processScenario = (scenario: Scenario): unknown => {
35	  const results = scenario.steps.map(quoteStep);
36	  return { results };
37	};
